import{_ as i,o as a,c as t,ag as r}from"./chunks/framework.DL-RKwfR.js";const c=JSON.parse('{"title":"企业管理员（看这里）","description":"","frontmatter":{"title":"企业管理员（看这里）","category":"快速上手","order":3,"lastUpdated":"2026-03-15T08:38:42.338Z"},"headers":[],"relativePath":"快速上手/企业管理员看这里.md","filePath":"快速上手/企业管理员看这里.md"}'),e={name:"快速上手/企业管理员看这里.md"};function o(n,l,p,s,h,d){return a(),t("div",null,[...l[0]||(l[0]=[r('<h1 id="企业管理员-看这里" tabindex="-1">企业管理员（看这里） <a class="header-anchor" href="#企业管理员-看这里" aria-label="Permalink to &quot;企业管理员（看这里）&quot;">​</a></h1><h1 id="管理员-如何快速启动团队训练和进行日常管理" tabindex="-1">管理员：如何快速启动团队训练和进行日常管理 <a class="header-anchor" href="#管理员-如何快速启动团队训练和进行日常管理" aria-label="Permalink to &quot;管理员：如何快速启动团队训练和进行日常管理&quot;">​</a></h1><p>练练提供了包含员工管理、团队数据查看等常见的管理功能，为了方便您快速启动团队使用练练，和进行日常的训练效果跟踪等，下面将会对日常管理功能和注意事项进行说明。</p><h2 id="管理入口在哪里" tabindex="-1">管理入口在哪里 <a class="header-anchor" href="#管理入口在哪里" aria-label="Permalink to &quot;管理入口在哪里&quot;">​</a></h2><p>和常见的平台把使用和管理分开为两个不同的系统不同，<strong>练练日常管理工作也是基于小程序来实现的</strong>。</p><p>如果你被分配了<strong>管理员或数据监察员</strong>（角色说明在下面），就会如右图所示位置看到对应的管理入口。</p><h2 id="什么是管理员和数据监察员" tabindex="-1">什么是管理员和数据监察员 <a class="header-anchor" href="#什么是管理员和数据监察员" aria-label="Permalink to &quot;什么是管理员和数据监察员&quot;">​</a></h2><p>管理员：</p><ul><li>类似于咱们公司内的部门经理，<strong>对本部门和下级部门的人员具有全部的管理能力</strong>。</li><li>可以邀请人员加入本部门，可以删除部门内员工。</li><li>可以查看本部门和下级部门所有人的练习数据等。</li><li>每个部门只能设置一个管理员，一个员工可以兼任多个部门管理员。</li></ul><p>数据监察员：</p><ul><li>定位为给团队内负责考核的人员提供查询对应练习数据的权限。</li><li><strong>数据监察员不具备除数据查看外其它所有的权限。</strong></li><li>一个部门可以设置多个数据监察员。</li><li>一个员工可以兼任部门管理员的同时也可以兼任多个部门的数据监察员。</li></ul><h2 id="日常管理流程" tabindex="-1">日常管理流程 <a class="header-anchor" href="#日常管理流程" aria-label="Permalink to &quot;日常管理流程&quot;">​</a></h2><h2 id="如何设计和创建部门" tabindex="-1">如何设计和创建部门 <a class="header-anchor" href="#如何设计和创建部门" aria-label="Permalink to &quot;如何设计和创建部门&quot;">​</a></h2><p>建议对照公司的管理层级来进行对应的部门设计，因为不管是管理员还是数据检查者，管理权限都是自上而下进行穿透的，根据管理需要，可以按照组织架构或职能结构来设计。</p><p>下面是两个不同的设计方式参考</p><p><strong>按照组织架构设计：</strong></p><ul><li>默认部门（默认创建，作为根部门，可以改名）</li><li>北京分公司</li><li>服务顾问</li><li>销售经理</li><li>销售一组</li><li>销售二组</li><li>上海分公司</li><li>服务顾问</li><li>销售经理</li><li>广州分公司</li><li>客户体验跟踪</li></ul><p><strong>按照职能结构设计：</strong></p><ul><li>默认部门（默认创建，作为根部门，可以改名）</li><li>顾问团队</li><li>朝阳店</li><li>海淀店</li><li>东城店</li><li>理疗服务团队</li><li>服务培训部</li><li>朝阳店</li><li>海淀店</li><li>东城店</li></ul><p>在您设计好部门层级后，告知练练的对接人员，目前部门的管理和管理员的设置由练练团队代为完成。</p><h2 id="如何添加和删除员工" tabindex="-1">如何添加和删除员工 <a class="header-anchor" href="#如何添加和删除员工" aria-label="Permalink to &quot;如何添加和删除员工&quot;">​</a></h2><p>点击企业Tab中的邀请成员入口，进入员工管理列表。</p><p><strong>只有管理员可以使用员工管理和邀请功能，数据监察员不具备该功能。</strong></p><p>点击“邀请成员加入企业”后，将如下邀请码分享给员工，扫码即可加入。</p><ul><li>员工可选择生成邀请码的管理员所管理的所有部门之一加入。</li><li>请注意不要外泄邀请码，可能造成外部人员加入。</li></ul><h2 id="如何查看员工的练习记录和报告" tabindex="-1">如何查看员工的练习记录和报告 <a class="header-anchor" href="#如何查看员工的练习记录和报告" aria-label="Permalink to &quot;如何查看员工的练习记录和报告&quot;">​</a></h2><p>除查看团队练习排行榜外，还可以查看员工每次练习对话中的对话记录和练习报告，明确了解每一个员工的在练习中不同场景的强弱点点，及时对应的对员工进行管理辅导。</p><p>数据相关功能<strong>管理员和数据监察员都可以访问。</strong></p><p>第一步：选择查看数据还是排行榜。</p><p>第二步：查看练习数据</p><p>进入员工列表</p><p>点击练习记录，查看改次练习的对话和报告</p><p>第三步：查看对话</p><p>查看练习报告</p><p>报告包含了</p><ol><li>总的练习评分。</li><li>说服力/销售能力、说话流利度等5个维度不必同评估值。</li><li>最终评价和建议。</li></ol><h2 id="其它常见问题q-a" tabindex="-1">其它常见问题Q&amp;A <a class="header-anchor" href="#其它常见问题q-a" aria-label="Permalink to &quot;其它常见问题Q&amp;A&quot;">​</a></h2><ul><li><strong>Q：团队有超级管理员吗？就是可以查看团队所有部门、所有人的练习数据的，也可以管理所有人。</strong></li></ul><p>系统不存在超级管理员这样一个角色，但是，每个团队都可以设置一个根部门（通常叫默认部门），其它所有的部门和员工都可以放到根部门下面，那么，跟部门的管理员，就是事实上的超级管理员。</p><ul><li><strong>部门的设置数量、层级有限制吗？</strong></li></ul><p>暂时没有限制，但是为了方便和简化管理，建议您在设计时候遵循以下几个原则。</p><ol><li>部门层级深度不要超过3层。例如：/总部/A省分公司/销售部/销售一组/KA</li><li>单个部门预计加入人员数量不超过30人。</li><li>每个部门都设置对应的管理员，可以让其对本部门的员工进行添加或删除等，降低根部门管理员（即上文提到的超级管理员）日常管理复杂度。</li></ol>',42)])])}const _=i(e,[["render",o]]);export{c as __pageData,_ as default};
